// ================================================================
// input_digit.h
// Hardcoded input image in fm_t (ap_fixed<16,6>) format.
// Included directly into lenet5_mnist.h so the HLS top-level
// has a default input available at synthesis and simulation time.
//
// TO CHANGE THE INPUT DIGIT:
//   1. Change DIGIT_LABEL to whichever digit you drew (0-9)
//   2. Edit INPUT_IMAGE rows — ON = white pixel, OFF = black
//   3. Re-run C Simulation / Synthesis — no other file changes needed
// ================================================================

