// ================================================================
// >>> CHANGE THIS to match the digit drawn below <<<
// ================================================================
#define DIGIT_LABEL  5

// ================================================================
// Pixel constants in fm_t = ap_fixed<16,6>
//   ON  = fm_t(1.0)  — white / ink pixel
//   OFF = fm_t(0.0)  — black / background pixel
// ================================================================
